import React from 'react';
import Navbar from './commponents/pages/Navbar';
import './App.css';

function App() {
  return (
    <div className="App" style={{ backgroundColor: '#0f172a', minHeight: '100vh', margin: 0, padding: 0 }}>
      <Navbar />
      <main style={{ padding: '2rem', color: '#fff', textAlign: 'center', fontFamily: 'Inter, sans-serif' }}>
        <h1 style={{ fontSize: '3.5rem', marginTop: '6rem', marginBottom: '1rem', background: 'linear-gradient(135deg, #00f2fe 0%, #4facfe 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
          Welcome to Jaggry We App
        </h1>
        <p style={{ color: '#94a3b8', fontSize: '1.25rem', maxWidth: '600px', margin: '0 auto' }}>
          A premium, fully responsive web application experience. Try resizing your browser to see the mobile navigation in action.
        </p>
      </main>
    </div>
  );
}

export default App;
